<script setup lang="ts">defineProps<{items:{label:string;icon:string;value:string}[];active:string}>();defineEmits<{select:[string]}>()</script><template><aside class="xj-card" style="padding:9px;display:grid;gap:5px"><button v-for="i in items" :key="i.value" @click="$emit('select',i.value)" :style="{height:'42px',border:0,borderRadius:'10px',background:active===i.value?'#EAF9F0':'transparent',color:active===i.value?'var(--xj-green-deep)':'var(--xj-muted)',fontWeight:active===i.value?750:550,display:'flex',alignItems:'center',gap:'10px',padding:'0 12px'}"><img :src="i.icon" class="xj-icon sm"/>{{i.label}}</button></aside></template>
